-- FAQ items pentru toate cele 30 de rugăciuni
-- Generat cu gen_faq.py
BEGIN;

UPDATE ec_rugaciuni SET faq_items = '[{"question": "Când se citește Rugăciunea de vindecare trupească?", "answer": "Se poate citi oricând, dar mai ales dimineața, înainte de tratament sau în momentele de durere. Se recomandă rostirea cu credință și liniște sufletească, de câte ori simțiți nevoia."}, {"question": "Câte zile se citește rugăciunea pentru vindecare?", "answer": "Tradiția ortodoxă recomandă citirea timp de 40 de zile consecutive. Poate fi continuată mai mult dacă vindecarea întârzie, cu nădejde și răbdare."}, {"question": "Rugăciunea de vindecare poate înlocui tratamentul medical?", "answer": "Nu. Rugăciunea completează îngrijirea medicală, nu o înlocuiește. Biserica Ortodoxă îndeamnă la folosirea ambelor mijloace: rugăciunea și medicina, amândouă fiind daruri ale lui Dumnezeu."}]' WHERE slug = 'rugaciune-de-vindecare-trupeasca';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Cui este adresată rugăciunea pentru sănătate și tămăduire?", "answer": "Rugăciunea este adresată Maicii Domnului, ocrotitoarea bolnavilor, și Sfântului Pantelimon, cel mai venerat sfânt tămăduitor din tradiția ortodoxă."}, {"question": "De ce se cere ajutorul Sfântului Pantelimon pentru sănătate?", "answer": "Sfântul Pantelimon a fost medic în viața pământească și a vindecat gratuit pe cei săraci. Nenumărate vindecări miraculoase i-au fost atribuite după moarte, de aceea este numit Doctor fără de arginți și patron al bolnavilor."}, {"question": "Ce înseamnă făgăduința din această rugăciune?", "answer": "Credinciosul promite că, după vindecare, va trăi în mulțumire și în slujba aproapelui. Această ofrandă a recunoștinței face parte din dialogul de credință cu Dumnezeu."}]' WHERE slug = 'rugaciune-pentru-sanatate-si-tamaduire';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Cine poate rosti rugăciunea pentru cel bolnav?", "answer": "Orice persoană poate rosti această rugăciune pentru cineva drag bolnav: soț, soție, copil, părinte sau prieten. Rugăciunea de mijlocire pentru alții este una dintre formele cele mai înalte de dragoste creștină."}, {"question": "Este eficientă rugăciunea pentru altcineva?", "answer": "Da. Tradiția ortodoxă confirmă puterea rugăciunii de mijlocire. Sfinții mijlocesc pentru noi înaintea lui Dumnezeu, iar noi putem mijloci unii pentru alții prin rugăciune sinceră."}, {"question": "Ce facem când cel bolnav nu se vindecă?", "answer": "Rugăciunea cere vindecarea dacă este spre folosul sufletului. Uneori Dumnezeu îngăduie boala ca mijloc de curățire sau de mântuire. Rugăciunea aduce întotdeauna mângâiere, răbdare și pace, chiar dacă vindecarea fizică nu vine imediat."}]' WHERE slug = 'rugaciune-pentru-cel-bolnav';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "De ce este Sfântul Nectarie cunoscut ca vindecător al cancerului?", "answer": "Numeroase vindecări miraculoase de cancer au fost documentate la mormântul și prin rugăciunile Sfântului Nectarie din Eghina, canonizat în 1961. El este considerat sfântul veacului nostru, cu o putere deosebită de mijlocire pentru bolile grave."}, {"question": "Unde se află moaștele Sfântului Nectarie?", "answer": "Moaștele Sfântului Nectarie se află la Mănăstirea Sfânta Treime din insula Eghina, Grecia, unde a trăit și a adormit în 1920. Milioane de pelerini vin anual să se închine."}, {"question": "Când este ziua Sfântului Nectarie?", "answer": "Sfântul Nectarie este prăznuit pe 9 noiembrie. În această zi, credincioșii participă la slujbe speciale și se roagă pentru tămăduire prin mijlocirea sa."}]' WHERE slug = 'acatistul-sfantului-nectarie-vindecare';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Când se citește rugăciunea înainte de operație?", "answer": "Se citește în seara sau dimineața dinaintea operației, când sufletul caută liniște și nădejde. Poate fi citită de pacient sau de rudele care se roagă pentru el."}, {"question": "De ce se roagă pentru mâinile medicilor?", "answer": "Tradiția ortodoxă vede în medicul care operează un instrument al lui Dumnezeu. Dumnezeu a dăruit oamenilor înțelepciunea medicinei, iar rugăciunea cere ca mâinile medicilor să fie ghidate de harul divin în fiecare decizie."}, {"question": "Există un sfânt patron al celor care se operează?", "answer": "Da. Sfântul Mare Mucenic Pantelimon, Sfântul Luca al Crimeei (el însuși chirurg) și Sfinții Cosma și Damian sunt sfinții tămăduitori chemați în ajutor înainte de orice intervenție medicală."}]' WHERE slug = 'rugaciune-inainte-de-operatie';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Ajută rugăciunea în depresie și anxietate?", "answer": "Da. Studii medicale moderne confirmă că rugăciunea și practica spirituală reduc semnificativ anxietatea și depresia. Rugăciunea aduce pacea lui Hristos — o pace care întrece orice înțelegere omenească."}, {"question": "Rugăciunea înlocuiește tratamentul psihiatric?", "answer": "Nu. Sănătatea mintală poate necesita tratament medical și psihoterapie. Rugăciunea le completează și le susține, dar nu le înlocuiește. A cere ajutor medical este un act de responsabilitate, nu de lipsă de credință."}, {"question": "Ce psalm se citește pentru liniștea minții?", "answer": "Psalmul 22 (Domnul este Păstorul meu) și Psalmul 90 sunt recomandate pentru liniștea minții. De asemenea, rugăciunea lui Iisus — Doamne Iisuse Hristoase, Fiul lui Dumnezeu, miluiește-mă pe mine, păcătosul — rostită repetat, aduce pace profundă."}]' WHERE slug = 'rugaciune-pentru-sanatatea-mintii';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Cum se roagă un părinte pentru copilul bolnav?", "answer": "Rugăciunea părintelui pentru copil este dintre cele mai puternice rugăciuni. Se citește cu lacrimi și cu inima zdrobită, cerând milă și tămăduire. Tradiția recomandă și aprinderea unei lumânări la biserică și participarea la Sfânta Liturghie."}, {"question": "La ce sfânt se roagă pentru copii bolnavi?", "answer": "Sfântul Pantelimon, Sfinții Cosma și Damian și Maica Domnului sunt cei mai invocați pentru vindecarea copiilor. De asemenea, Sfântul Nectarie din Eghina a vindecat mulți copii bolnavi."}, {"question": "Ce altceva pot face părinții pe lângă rugăciune?", "answer": "Pe lângă rugăciune, părinții pot aduce copilul la biserică pentru a fi uns cu Sfântul Maslu, pot cere preotului să facă rugăciuni speciale pentru bolnav și pot posta în măsura puterilor lor ca jertfă pentru sănătatea copilului."}]' WHERE slug = 'rugaciune-pentru-copil-bolnav';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "De ce este importantă rugăciunea de mulțumire după vindecare?", "answer": "Rugăciunea de mulțumire completează ciclul dialogului cu Dumnezeu. Cei zece leproși vindecați de Iisus, dintre care unul singur s-a întors să mulțumească, ne arată că recunoștința este parte esențială a credinței."}, {"question": "Cum se mulțumește lui Dumnezeu pentru vindecare?", "answer": "Mulțumirea se exprimă prin rugăciune, prin participarea la Sfânta Liturghie, prin aprinderea unei lumânări sau printr-un act de milostenie. Unii credincioși fac și un pelerinaj la un loc sfânt ca semn de recunoștință."}, {"question": "Ce făgăduință se face lui Dumnezeu după vindecare?", "answer": "Rugăciunea menționează angajamentul de a folosi sănătatea redată în slujba lui Dumnezeu și a aproapelui. A trăi sănătos cu recunoștință și în slujba celorlalți este cel mai frumos mod de a-I mulțumi lui Dumnezeu."}]' WHERE slug = 'rugaciune-de-multumire-dupa-vindecare';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "La ce oră se citesc rugăciunile de dimineață?", "answer": "Rugăciunile de dimineață se citesc imediat după trezire, înainte de a mânca sau de a folosi telefonul. Ideal dimineața devreme, dar pot fi citite și mai târziu dacă programul nu permite."}, {"question": "Cât durează rânduiala de rugăciune de dimineață?", "answer": "Rânduiala completă din Ceaslov durează 15-20 de minute. Se poate scurta în zilele aglomerate la 5-10 minute, citind rugăciunile esențiale. Important este să nu sărim complet peste rugăciunea de dimineață."}, {"question": "De unde provine rânduiala rugăciunilor de dimineață?", "answer": "Rânduiala rugăciunilor de dimineață provine din Ceaslovul ortodox, o carte de rugăciuni cu vechi tradiție monahală. Ea a fost adaptată de-a lungul secolelor pentru uzul credincioșilor mireni."}]' WHERE slug = 'rugaciune-de-dimineata-ortodoxa';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Este suficientă o rugăciune scurtă de dimineață?", "answer": "Da. Sfinții Părinți spun că rugăciunea scurtă dar sinceră este mai valoroasă decât una lungă rostită mecanic. Dacă nu avem timp pentru rânduiala completă, chiar și câteva minute de rugăciune sinceră sunt de mare folos."}, {"question": "Ce rugăciune scurtă pot rosti dimineața când mă grăbesc?", "answer": "Rugăciunea lui Iisus — Doamne Iisuse Hristoase, Fiul lui Dumnezeu, miluiește-mă pe mine, păcătosul — poate fi rostită oricând și oriunde. De asemenea, această rugăciune scurtă sau Tatăl nostru sunt suficiente pentru diminețile aglomerate."}, {"question": "Cum mă obișnuiesc să mă rog în fiecare dimineață?", "answer": "Sfinții recomandă să legăm rugăciunea de un obicei deja existent: imediat după trezire, înainte de cafea sau de telefon. Chiar și 3-5 minute zilnic, constant, formează o rânduială sănătoasă."}]' WHERE slug = 'rugaciune-dimineata-scurta';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Ce înseamnă să binecuvântezi ziua prin rugăciune?", "answer": "Rugăciunea de dimineață sfințește începutul zilei, punând toate activitățile sub ocrotirea lui Dumnezeu. Este ca și cum ai cere permisiunea și binecuvântarea lui Dumnezeu înainte de a porni la drum."}, {"question": "Rugăciunea de dimineață îmbunătățește starea de spirit?", "answer": "Da. Studii psihologice și spirituale arată că practica rugăciunii dimineața reduce anxietatea, crește starea de bine și aduce un sentiment de scop și direcție pentru ziua ce urmează."}, {"question": "Pot rosti rugăciunea de dimineață și în drum spre serviciu?", "answer": "Da. Rugăciunea nu necesită neapărat un loc special. Poate fi rostită în minte sau cu glas mic în transport, în timp ce mergeți pe jos sau în orice moment de liniște din dimineața dvs."}]' WHERE slug = 'rugaciune-dimineata-pentru-zi-buna';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "De ce ne rugăm Maicii Domnului dimineața?", "answer": "Maica Domnului este Ocrotitoarea creștinilor și Mijlocitoarea noastră înaintea lui Hristos. Rugăciunea de dimineață către ea cere acoperământul omoforul ei sfânt pentru întreaga zi."}, {"question": "Ce este omoforul Maicii Domnului menționat în rugăciune?", "answer": "Omoforul este un veșmânt liturgic simbolic. Expresia acoperă-mă cu omoforul tău din rugăciune înseamnă acoperă-mă cu ocrotirea ta, pune-mă sub paza ta maternă. Este o expresie de alint spiritual."}, {"question": "Când este cea mai importantă zi de rugăciune către Maica Domnului?", "answer": "Sâmbăta este ziua tradițional dedicată Maicii Domnului în Ortodoxie. De asemenea, 15 august (Adormirea Maicii Domnului), 8 septembrie (Nașterea Maicii Domnului) și alte praznice mariale sunt zile de rugăciune intensă către ea."}]' WHERE slug = 'rugaciunea-dimineata-catre-maica-domnului';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Cine a fost Sfântul Vasile cel Mare?", "answer": "Sfântul Vasile cel Mare (330-379) a fost Arhiepiscopul Cezareei Capadociei și unul dintre cei mai mari Părinți ai Bisericii. A scris Liturghia care îi poartă numele și mai multe rânduieli de rugăciune, inclusiv rânduiala de dimineață."}, {"question": "Ce caracterizează rugăciunile Sfântului Vasile cel Mare?", "answer": "Rugăciunile Sfântului Vasile se remarcă prin profunzime teologică, bogăție de expresie și caldă evlavie. Ele combină lauda lui Dumnezeu cu smerenia omului și cererea de ajutor în viața practică."}, {"question": "Cum se citesc rugăciunile de dimineață ale Sfântului Vasile?", "answer": "Se citesc în picioare, cu fața spre Răsărit dacă este posibil, cu atenție și evlavie. Este important să fie rostite cu înțelegere, nu mecanic, lăsând cuvintele să pătrundă în inimă."}]' WHERE slug = 'rugaciunea-dimineata-sfantul-vasile';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Când se citesc rugăciunile de seară ortodoxe?", "answer": "Rugăciunile de seară se citesc înainte de culcare, după ce s-au terminat treburile zilei. Ideal între orele 21:00-22:00, dar pot fi citite oricând seara, în liniște."}, {"question": "De ce cerem iertare seara în rugăciune?", "answer": "Seara facem un examen de conștiință al zilei trecute: ce am greșit în gând, cuvânt sau faptă. Cererea de iertare seara curățește sufletul înainte de somn și ne pregătește pentru o nouă zi."}, {"question": "Ce se întâmplă dacă adorm în timp ce mă rog?", "answer": "Nu este o greșeală. Sfinții Părinți spun că dacă ai adormit rugându-te, este un semn că rugăciunea ți-a adus pacea și odihna de care aveai nevoie. Dumnezeu primește și rugăciunea celui care adoarme cu gândul la El."}]' WHERE slug = 'rugaciune-de-seara-ortodoxa';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Este păcat dacă nu mă rog seara cu rânduiala completă?", "answer": "Nu. Dumnezeu privește la inimă, nu la cantitate. O rugăciune scurtă dar sinceră are mai mare valoare decât una lungă rostită din obișnuință. Important este să nu adormi fără să mulțumești lui Dumnezeu pentru ziua trecută."}, {"question": "Ce rugăciune minimă trebuie rostită seara?", "answer": "Tatăl Nostru și o rugăciune scurtă de mulțumire și cerere de iertare sunt suficiente. Rugăciunea lui Iisus, repetată de câteva ori cu evlavie, poate înlocui rânduiala completă în zilele aglomerate."}, {"question": "Pot să mă rog și în pat înainte de somn?", "answer": "Da. Deși tradiția recomandă rugăciunea în picioare, rugăciunea în pat înainte de somn este acceptată, mai ales pentru cei bolnavi sau prea obosiți. Dumnezeu ascultă rugăciunea inimii, nu neapărat a trupului."}]' WHERE slug = 'rugaciune-seara-scurta';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Este important să ne rugăm în familie seara?", "answer": "Da. Rugăciunea în familie este una dintre cele mai puternice practici spirituale. Ea unește inimile, creează o atmosferă de pace și transmite credința copiilor prin exemplul viu al părinților."}, {"question": "De la ce vârstă pot participa copiii la rugăciunea de seară?", "answer": "Copiii pot participa de la cea mai mică vârstă, chiar de când nu înțeleg cuvintele. Ei absorb atmosfera de rugăciune și învață că Dumnezeu este parte din viața de zi cu zi a familiei."}, {"question": "Cum facem rugăciunea de seară în familie dacă membri au programe diferite?", "answer": "Dacă nu toți pot fi prezenți, rugăciunea se poate face cu cine este acasă, incluzând și pe cei absenți în rugăciune. Chiar și o rugăciune scurtă comună înainte de cină poate înlocui rugăciunea de seară formală."}]' WHERE slug = 'rugaciune-seara-pentru-familie';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "De ce este mulțumirea importantă în rugăciunea de seară?", "answer": "Mulțumirea schimbă perspectiva asupra zilei: în loc să vedem doar greutățile, devenim conștienți de binefacerile pe care le-am primit. Sfinții spun că mulțumirea aduce mai multă binecuvântare decât orice cerere."}, {"question": "Cum practic recunoștința față de Dumnezeu?", "answer": "O practică utilă: înainte de rugăciunea de seară, gândește-te la trei lucruri concrete pentru care mulțumești lui Dumnezeu în ziua aceea. Pot fi lucruri mici: o discuție bună, un moment frumos, sănătatea, o masă bună."}, {"question": "Ce înseamnă binefacerile văzute și nevăzute din rugăciune?", "answer": "Binefacerile văzute sunt cele pe care le observăm: sănătatea, hrana, familia. Cele nevăzute sunt pericolele de care am fost feriți fără să știm, ispitele care ne-au ocolit, îngerul păzitor care ne-a ocrotit fără să îl vedem."}]' WHERE slug = 'rugaciunea-seara-cu-multumire';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "De ce este important ca copiii să se roage înainte de somn?", "answer": "Rugăciunea înainte de somn formează un obicei spiritual sănătos și transmite copilului că Dumnezeu este prezent și noaptea. De asemenea, aduce liniște sufletească și un somn mai odihnitor."}, {"question": "Ce este îngerul păzitor menționat în rugăciunea copiilor?", "answer": "Tradiția ortodoxă învață că fiecare om are un înger păzitor din momentul nașterii, care îl însoțește toată viața. Îngerul ne apără de rele și mijlocește pentru noi înaintea lui Dumnezeu."}, {"question": "Cum îi învăț pe copii să se roage?", "answer": "Cel mai eficient mod este exemplul: rugați-vă cu ei și lăsați-i să vă vadă rugându-vă. Începeți cu rugăciuni scurte și simple, lăsați-i să spună cu propriile cuvinte ce vor de la Dumnezeu și faceți din rugăciune un moment cald și așteptat."}]' WHERE slug = 'rugaciune-inainte-de-culcare-copii';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "De ce se citește Psalmul 22 în momente de suferință?", "answer": "Psalmul 22 exprimă încrederea deplină în Dumnezeu chiar și în valea umbrei morții — o metaforă pentru cele mai grele momente ale vieții. Cuvintele nu mă tem de niciun rău, căci Tu ești cu mine aduc mângâiere profundă în suferință."}, {"question": "Psalmul 22 este același cu 23 din Biblia protestantă?", "answer": "Da. Numerotarea psalmilor diferă ușor între Biblia ortodoxă (Septuaginta) și Biblia protestantă (Masoretică). Psalmul 22 ortodox corespunde Psalmului 23 protestant — Domnul este Păstorul meu."}, {"question": "Când se citește Psalmul 22 la slujbele ortodoxe?", "answer": "Psalmul 22 se citește la Sfânta Liturghie, la slujba pentru cei adormiți (parastas) și în cadrul Paraclesului. Este asociat atât cu mângâierea celor vii, cât și cu pomenirea și odihna celor adormiți."}]' WHERE slug = 'psalmul-22-domnul-este-pastorul-meu';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "De ce se citește Psalmul 50 în fiecare zi la Utrenie?", "answer": "Psalmul 50 este psalmul pocăinței, citit zilnic în rânduiala Utreniei ortodoxe pentru că pocăința este o stare permanentă a creștinului. El ne amintește în fiecare zi că avem nevoie de mila lui Dumnezeu."}, {"question": "Cum a scris David Psalmul 50?", "answer": "Psalmul 50 a fost scris de regele David după căderea sa în păcatul cu Batșeba și uciderea lui Urie. Profetul Natan i-a descoperit păcatul, iar David a compus acest psalm ca expresie a pocăinței sale sincere."}, {"question": "Ce înseamnă inimă curată zidește întru mine, Dumnezeule din Psalmul 50?", "answer": "David cere lui Dumnezeu o transformare lăuntrică totală — nu simpla curățire a unui păcat, ci o inimă nouă, recreată de Dumnezeu. Este cererea pentru o schimbare profundă de caracter, nu doar de comportament."}]' WHERE slug = 'psalmul-50-miluieste-ma-dumnezeule';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "De ce se citește Psalmul 90 pentru apărare și protecție?", "answer": "Psalmul 90 descrie protecția divină completă: Cel ce locuiește în ajutorul Celui Preaînalt va fi sub acoperământul Dumnezeului Cerului. Tradiția ortodoxă îl citește pentru protecție împotriva bolilor, pericolelor și duhurilor rele."}, {"question": "Cine și când citește Psalmul 90?", "answer": "Psalmul 90 este citit de credincioși în momente de frică, pericol sau boală. Se citește și la sfințirea casei, la binecuvântarea unui drum și în rugăciunile pentru apărarea față de rele."}, {"question": "Câte ori se citește Psalmul 90 pentru a fi eficient?", "answer": "Nu există o număr magic de repetări. Tradiția recomandă citirea cu credință și evlavie. Unii credincioși îl citesc de 3 ori (în cinstea Sfintei Treimi), alții de 40 de zile consecutiv pentru o intenție specială."}]' WHERE slug = 'psalmul-90-cel-ce-locuieste-in-ajutorul-celui-preainalt';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "De ce se citește Psalmul 102 pentru sănătate?", "answer": "Psalmul 102 laudă pe Dumnezeu pentru că vindecă toate bolile tale — un verset cheie care a consacrat acest psalm ca rugăciune de vindecare și mulțumire pentru sănătate în tradiția ortodoxă."}, {"question": "Psalmul 102 se citește înainte sau după vindecare?", "answer": "Poate fi citit și înainte (ca cerere de vindecare) și după (ca mulțumire). Versetul Cel ce vindecă toate bolile tale îl face potrivit atât pentru cerere cât și pentru laudă și recunoștință."}, {"question": "Ce alte psalmi se citesc pentru sănătate?", "answer": "Psalmul 6 (rugăciune în boală), Psalmul 22 (mângâiere în suferință), Psalmul 30 și Psalmul 90 sunt recomandate în tradiția ortodoxă pentru vindecare și sănătate, alături de Psalmul 102."}]' WHERE slug = 'psalmul-102-binecuvinteaza-suflete-al-meu-pe-domnul';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Ce înseamnă casa ca biserică mică menționat în rugăciune?", "answer": "Expresia vine din tradiția patristică. Sfântul Ioan Gură de Aur numea familia bisericuță mică. O casă în care se roagă, se citește din Scriptură și se trăiește în dragoste creștină devine un loc sfânt, un altar domestic."}, {"question": "Cum sfințim casa cu rugăciunea?", "answer": "Prin rugăciunea zilnică, prin sfințirea casei cu agheasmă (apă sfințită), prin ținerea unui colț cu icoane și candela aprinsă. Preotul poate veni să sfințească casa, mai ales la începutul anului sau la mutarea într-o locuință nouă."}, {"question": "Rugăciunea pentru familie ajută în conflictele familiale?", "answer": "Da. Rugăciunea nu rezolvă automat conflictele, dar schimbă inimile celor care se roagă. Ea aduce smerenie, capacitate de iertare și dorința de reconciliere — ingredientele esențiale pentru rezolvarea oricărui conflict familial."}]' WHERE slug = 'rugaciune-pentru-familie-si-casa';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Ce este Taina Sfintei Cununii menționată în rugăciune?", "answer": "Sfânta Cununie este una dintre cele șapte Taine ale Bisericii Ortodoxe. Prin ea, doi oameni se unesc în fața lui Dumnezeu într-o legătură spirituală eternă, nu doar o formalitate socială sau civilă."}, {"question": "Cum rugăciunea pentru soț sau soție întărește căsătoria?", "answer": "Rugăciunea pentru celălalt exprimă dragostea dezinteresată — dorim binele lui, nu al nostru. Ea creează o legătură spirituală profundă și aduce pe Dumnezeu în centrul căsătoriei."}, {"question": "Ce sfânt ocrotește căsătoriile și familiile?", "answer": "Sfânta Filofteia, Sfântul Ioan Gură de Aur (patron al familiei creștine) și Maica Domnului sunt cei mai invocați pentru binecuvântarea căsătoriei. Rugăciunea la icoana Maicii Domnului este recomandată în special pentru problemele familiale."}]' WHERE slug = 'rugaciune-pentru-sot-sotie';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Rugăciunea părinților ajută copiii chiar dacă aceștia nu știu?", "answer": "Da. Tradiția ortodoxă și mulți duhovnici confirmă că rugăciunea părinților pentru copii are o putere deosebită, indiferent dacă copiii știu sau nu de ea. Dragostea părintească în rugăciune este una dintre formele cele mai curate de mijlocire."}, {"question": "De la ce vârstă putem ruga pentru copii?", "answer": "Rugăciunea pentru copii poate începe chiar din timpul sarcinii. Mulți părinți ortodocși se roagă pentru copiii lor nenăscuți, ținând o viață spirituală intensă în timpul sarcinii."}, {"question": "Cum ajut copilul să crească în credință?", "answer": "Cel mai eficient mod este exemplul viu: rugați-vă împreună, duceți-i la biserică, citiți împreună din Biblie sau din viețile sfinților. Credința nu se predă teoretic — se transmite prin trăire."}]' WHERE slug = 'rugaciune-pentru-copii';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Ce spune Biblia despre cinstirea părinților?", "answer": "A cinsti pe tatăl tău și pe mama ta este a cincea poruncă din Decalog. Sfântul Apostol Pavel o menționează drept prima poruncă cu făgăduință — celor ce o împlinesc li se promite viață lungă și bună."}, {"question": "Cum ajutăm părinții bolnavi sau în vârstă prin rugăciune?", "answer": "Rugăciunea regulată pentru ei, participarea la Sfânta Liturghie cu intenție specială pentru sănătatea lor, cererea de Maslu și parastasele pentru cei adormiți sunt mijloace spirituale concrete de ajutor."}, {"question": "Ce facem spiritual pentru părinții care au trecut la cele veșnice?", "answer": "Pomenirile la Sfânta Liturghie, parastasele, milosteniile făcute în amintirea lor și rugăciunile de acasă continuă legătura spirituală cu cei adormiți. Tradiția ortodoxă crede că rugăciunile ajung la sufletele celor adormiți."}]' WHERE slug = 'rugaciune-pentru-parinti-batrani';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Ce cauzează conflictele în familie din perspectivă ortodoxă?", "answer": "Teologia ortodoxă identifică egocentrismul (iubirea de sine exagerată), mândria și lipsa de iertare ca rădăcini ale conflictelor familiale. Rugăciunea atacă tocmai aceste rădăcini, cultivând smerenia și iubirea."}, {"question": "Cum mă rog pentru reconcilierea cu un membru al familiei?", "answer": "Rugați-vă pentru persoana cu care sunteți în conflict, cerând lui Dumnezeu să schimbe inimile amândurora. Sfinții recomandă să ne rugăm mai mult pentru celălalt decât pentru noi înșine, cercând mai întâi propria noastră schimbare."}, {"question": "Există o rugăciune specială pentru reconciliere?", "answer": "Această rugăciune pentru pace în familie este potrivită. De asemenea, Psalmul 50 (rugăciunea pocăinței) și rugăciunea Tatăl nostru (care include iertați nouă greșelile noastre, precum și noi iertăm) sunt recomandate în procesul de reconciliere."}]' WHERE slug = 'rugaciune-pentru-pace-in-familie';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "Ajută rugăciunea la un examen important?", "answer": "Da. Rugăciunea aduce liniște sufletească, reduce anxietatea de performanță și ajută la concentrare. Studii psihologice confirmă că practicile spirituale îmbunătățesc performanța în situații de stres."}, {"question": "Ce sfânt se cheamă în ajutor înainte de examene?", "answer": "Sfântul Sava cel Sfințit, Sfântul Grigorie Teologul și Sfânta Ecaterina (patroana studenților) sunt invocați de elevi și studenți. De asemenea, Maica Domnului este chemată pentru limpezime a minții și ajutor la examene."}, {"question": "Rugăciunea înainte de examen funcționează fără pregătire?", "answer": "Rugăciunea nu înlocuiește studiul. Sfântul Ioan Gură de Aur spunea: Roagă-te ca și cum totul depinde de Dumnezeu, muncește ca și cum totul depinde de tine. Rugăciunea și pregătirea serioasă merg împreună."}]' WHERE slug = 'rugaciune-inainte-de-examen';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "De ce se citește rugăciunea înainte de a pleca la drum?", "answer": "Tradiția ortodoxă binecuvântează fiecare început de drum. Rugăciunea cere paza lui Dumnezeu și a îngerului păzitor pe toată calea, conștientizând că suntem vulnerabili în călătorie și avem nevoie de protecție divină."}, {"question": "Există un sfânt patron al călătorilor?", "answer": "Sfântul Cristofor este tradiționalmente patronul călătorilor și șoferilor. Sfântul Nicolaie este patronul marinarilor. Îngerul păzitor este invocat de fiecare credincios pentru protecție pe drum."}, {"question": "Se citește rugăciunea la drum și înainte de zbor cu avionul?", "answer": "Da, rugăciunea la drum se aplică oricărui tip de călătorie: cu mașina, trenul, avionul sau vaporul. Mulți credincioși fac semnul crucii și rostesc o rugăciune scurtă înainte de orice mijloc de transport."}]' WHERE slug = 'rugaciune-la-drum';
UPDATE ec_rugaciuni SET faq_items = '[{"question": "De ce îngăduie Dumnezeu necazurile în viața noastră?", "answer": "Teologia ortodoxă vede necazul ca pe un mijloc de purificare și creștere spirituală. Sfântul Apostol Pavel spune că necazul lucrează răbdare, răbdarea — experiență, experiența — nădejde. Dumnezeu nu trimite necazul, dar îl poate transforma în bine."}, {"question": "Cum rămân în credință când Dumnezeu pare că nu răspunde?", "answer": "Sfinții care au trecut prin cele mai mari încercări — Iov, David, apostolii — au menținut credința nu prin absența îndoielii, ci prin revenirea la rugăciune în ciuda ei. Strigătul Doamne, de ce? este el însuși o rugăciune."}, {"question": "Ce rugăciuni se citesc în momente de mare necaz și deznădejde?", "answer": "Psalmul 90, Acatistul Maicii Domnului, Psalmul 50 și Paraclisul Maicii Domnului sunt recomandate în momentele grele. De asemenea, participarea la Sfânta Liturghie și primirea Sfintei Împărtășanii aduc întărire sufleteasca în suferință."}]' WHERE slug = 'rugaciune-in-vreme-de-necaz';

-- Verificare
SELECT slug, faq_items IS NOT NULL as has_faq FROM ec_rugaciuni ORDER BY slug;

COMMIT;